'use client';

import {
  AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend, ReferenceLine,
} from 'recharts';
import { TrendingUp } from 'lucide-react';

// TODO: Backend — GET /api/analytics/share-timeline?range=7d&accountId=alex.creates
const timelineData = [
  { day: 'Mon Mar 9', reels: 412, posts: 138, stories: 67 },
  { day: 'Tue Mar 10', reels: 580, posts: 201, stories: 89 },
  { day: 'Wed Mar 11', reels: 349, posts: 155, stories: 54 },
  { day: 'Thu Mar 12', reels: 891, posts: 310, stories: 143 },
  { day: 'Fri Mar 13', reels: 1240, posts: 445, stories: 201 },
  { day: 'Sat Mar 14', reels: 987, posts: 388, stories: 178 },
  { day: 'Sun Mar 15', reels: 1547, posts: 521, stories: 234 },
];

const CustomTooltip = ({ active, payload, label }: any) => {
  if (!active || !payload?.length) return null;
  const total = payload.reduce((s: number, p: any) => s + (p.value || 0), 0);
  return (
    <div className="bg-white border border-zinc-200 rounded-xl shadow-dropdown p-3 min-w-[180px]">
      <p className="text-xs font-semibold text-zinc-500 mb-2">{label}</p>
      {payload.map((p: any) => (
        <div key={p.dataKey} className="flex items-center justify-between gap-4 mb-1">
          <div className="flex items-center gap-1.5">
            <span className="w-2 h-2 rounded-full" style={{ backgroundColor: p.color }} />
            <span className="text-xs text-zinc-600 capitalize">{p.dataKey}</span>
          </div>
          <span className="text-xs font-semibold text-zinc-800 tabular-nums">{p.value.toLocaleString()}</span>
        </div>
      ))}
      <div className="border-t border-zinc-100 mt-2 pt-2 flex justify-between">
        <span className="text-xs text-zinc-500">Total shares</span>
        <span className="text-xs font-bold text-zinc-900 tabular-nums">{total.toLocaleString()}</span>
      </div>
    </div>
  );
};

export default function ShareTimelineChart() {
  return (
    <div className="bg-white rounded-xl border border-zinc-200 shadow-card p-5 h-full">
      <div className="flex items-center justify-between mb-4">
        <div>
          <div className="flex items-center gap-2 mb-0.5">
            <TrendingUp size={16} className="text-violet-500" />
            <h3 className="text-[15px] font-semibold text-zinc-900">Share Volume — Last 7 Days</h3>
          </div>
          <p className="text-xs text-zinc-400">Breakdown by content type · Mon Mar 9 – Sun Mar 15</p>
        </div>
        <div className="flex items-center gap-1.5 text-xs text-green-600 font-semibold bg-green-50 px-2.5 py-1 rounded-full border border-green-100">
          <TrendingUp size={11} />
          +38.4% WoW
        </div>
      </div>

      <ResponsiveContainer width="100%" height={240}>
        <AreaChart data={timelineData} margin={{ top: 4, right: 4, left: -16, bottom: 0 }}>
          <defs>
            <linearGradient id="gradReels" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#7C3AED" stopOpacity={0.25} />
              <stop offset="95%" stopColor="#7C3AED" stopOpacity={0.02} />
            </linearGradient>
            <linearGradient id="gradPosts" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#EC4899" stopOpacity={0.22} />
              <stop offset="95%" stopColor="#EC4899" stopOpacity={0.02} />
            </linearGradient>
            <linearGradient id="gradStories" x1="0" y1="0" x2="0" y2="1">
              <stop offset="5%" stopColor="#F97316" stopOpacity={0.18} />
              <stop offset="95%" stopColor="#F97316" stopOpacity={0.02} />
            </linearGradient>
          </defs>
          <CartesianGrid stroke="hsl(var(--border))" strokeDasharray="3 3" vertical={false} />
          <XAxis
            dataKey="day"
            tick={{ fontSize: 11, fill: '#a1a1aa', fontFamily: 'DM Sans' }}
            tickLine={false}
            axisLine={false}
            tickFormatter={(v) => v.split(' ')[0]}
          />
          <YAxis
            tick={{ fontSize: 11, fill: '#a1a1aa', fontFamily: 'DM Sans' }}
            tickLine={false}
            axisLine={false}
            tickFormatter={(v) => v >= 1000 ? `${(v / 1000).toFixed(1)}k` : v}
          />
          <Tooltip content={<CustomTooltip />} />
          <ReferenceLine y={800} stroke="#F59E0B" strokeDasharray="4 2" strokeWidth={1} label={{ value: 'Avg', position: 'insideTopRight', fontSize: 10, fill: '#F59E0B' }} />
          <Area type="monotone" dataKey="reels" stroke="#7C3AED" strokeWidth={2} fill="url(#gradReels)" name="Reels" dot={false} activeDot={{ r: 4, fill: '#7C3AED' }} />
          <Area type="monotone" dataKey="posts" stroke="#EC4899" strokeWidth={2} fill="url(#gradPosts)" name="Posts" dot={false} activeDot={{ r: 4, fill: '#EC4899' }} />
          <Area type="monotone" dataKey="stories" stroke="#F97316" strokeWidth={2} fill="url(#gradStories)" name="Stories" dot={false} activeDot={{ r: 4, fill: '#F97316' }} />
          <Legend
            iconType="circle"
            iconSize={7}
            formatter={(v) => <span style={{ fontSize: 12, color: '#71717a', fontFamily: 'DM Sans' }}>{v}</span>}
          />
        </AreaChart>
      </ResponsiveContainer>
    </div>
  );
}