'use client';

import { useState } from 'react';
import Link from 'next/link';
import { usePathname } from 'next/navigation';
import AppLogo from '@/components/ui/AppLogo';
import {
  LayoutDashboard,
  Share2,
  Users,
  TrendingUp,
  FileImage,
  Bell,
  Settings,
  ChevronLeft,
  ChevronRight,
  Instagram,
  Zap,
  BarChart2,
} from 'lucide-react';
import Icon from '@/components/ui/AppIcon';


interface NavItem {
  label: string;
  href: string;
  icon: React.ElementType;
  badge?: number;
  group?: string;
}

const navItems: NavItem[] = [
  { label: 'Share Dashboard', href: '/share-tracking-dashboard', icon: LayoutDashboard, group: 'Overview' },
  { label: 'All Shares', href: '/share-tracking-dashboard', icon: Share2, badge: 47, group: 'Overview' },
  { label: 'Top Sharers', href: '/share-tracking-dashboard', icon: Users, group: 'Audience' },
  { label: 'Share Trends', href: '/share-tracking-dashboard', icon: TrendingUp, group: 'Audience' },
  { label: 'My Content', href: '/share-tracking-dashboard', icon: FileImage, group: 'Content' },
  { label: 'Viral Tracker', href: '/share-tracking-dashboard', icon: Zap, badge: 3, group: 'Content' },
  { label: 'Analytics', href: '/share-tracking-dashboard', icon: BarChart2, group: 'Reports' },
  { label: 'Alerts', href: '/share-tracking-dashboard', icon: Bell, badge: 5, group: 'Reports' },
];

const bottomItems: NavItem[] = [
  { label: 'Settings', href: '/share-tracking-dashboard', icon: Settings },
];

export default function Sidebar() {
  const [collapsed, setCollapsed] = useState(false);
  const pathname = usePathname();

  const groups = Array.from(new Set(navItems.map((i) => i.group)));

  return (
    <aside
      className={`
        fixed left-0 top-0 h-full z-30 bg-white border-r border-zinc-200
        flex flex-col sidebar-transition overflow-hidden
        ${collapsed ? 'w-16' : 'w-60'}
      `}
    >
      {/* Logo */}
      <div className={`flex items-center h-16 border-b border-zinc-100 px-4 ${collapsed ? 'justify-center' : 'gap-2'}`}>
        <div className="flex items-center gap-2 min-w-0">
          <AppLogo size={32} />
          {!collapsed && (
            <span className="font-semibold text-[15px] text-zinc-900 truncate leading-tight">
              InstaShare<span className="text-violet-600">Tracker</span>
            </span>
          )}
        </div>
      </div>

      {/* Connected account chip */}
      {!collapsed && (
        <div className="mx-3 mt-3 mb-1 px-3 py-2 rounded-lg bg-gradient-to-r from-violet-50 to-pink-50 border border-violet-100 flex items-center gap-2">
          <Instagram size={14} className="text-pink-500 shrink-0" />
          <span className="text-xs font-medium text-zinc-700 truncate">@alex.creates</span>
          <span className="ml-auto w-2 h-2 rounded-full bg-green-400 shrink-0" title="Connected" />
        </div>
      )}
      {collapsed && (
        <div className="flex justify-center mt-3 mb-1">
          <Instagram size={16} className="text-pink-500" />
        </div>
      )}

      {/* Nav groups */}
      <nav className="flex-1 overflow-y-auto scrollbar-thin px-2 pt-2 pb-2">
        {groups.map((group) => (
          <div key={group} className="mb-1">
            {!collapsed && (
              <p className="px-3 pt-3 pb-1 text-[10px] font-600 uppercase tracking-widest text-zinc-400 select-none">
                {group}
              </p>
            )}
            {collapsed && <div className="my-2 border-t border-zinc-100" />}
            {navItems
              .filter((i) => i.group === group)
              .map((item) => {
                const Icon = item.icon;
                const active = pathname === item.href && item.label === 'Share Dashboard';
                return (
                  <Link
                    key={item.label}
                    href={item.href}
                    title={collapsed ? item.label : undefined}
                    className={`
                      group relative flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium
                      transition-all duration-150 mb-0.5
                      ${active
                        ? 'bg-violet-50 text-violet-700'
                        : 'text-zinc-600 hover:bg-zinc-50 hover:text-zinc-900'
                      }
                      ${collapsed ? 'justify-center' : ''}
                    `}
                  >
                    {active && (
                      <span className="absolute left-0 top-1/2 -translate-y-1/2 w-0.5 h-5 rounded-r bg-violet-600" />
                    )}
                    <Icon
                      size={17}
                      className={`shrink-0 ${active ? 'text-violet-600' : 'text-zinc-400 group-hover:text-zinc-600'}`}
                    />
                    {!collapsed && (
                      <>
                        <span className="flex-1 truncate">{item.label}</span>
                        {item.badge !== undefined && (
                          <span className={`
                            text-[10px] font-semibold px-1.5 py-0.5 rounded-full leading-none
                            ${active ? 'bg-violet-200 text-violet-700' : 'bg-zinc-100 text-zinc-500'}
                          `}>
                            {item.badge}
                          </span>
                        )}
                      </>
                    )}
                    {collapsed && item.badge !== undefined && (
                      <span className="absolute top-1 right-1 w-1.5 h-1.5 rounded-full bg-violet-500" />
                    )}
                  </Link>
                );
              })}
          </div>
        ))}
      </nav>

      {/* Bottom items */}
      <div className="border-t border-zinc-100 px-2 py-2">
        {bottomItems.map((item) => {
          const Icon = item.icon;
          return (
            <Link
              key={item.label}
              href={item.href}
              title={collapsed ? item.label : undefined}
              className={`
                flex items-center gap-3 px-3 py-2 rounded-lg text-sm font-medium
                text-zinc-500 hover:bg-zinc-50 hover:text-zinc-800 transition-all duration-150
                ${collapsed ? 'justify-center' : ''}
              `}
            >
              <Icon size={17} className="shrink-0" />
              {!collapsed && <span>{item.label}</span>}
            </Link>
          );
        })}

        {/* User profile */}
        <div className={`mt-1 flex items-center gap-2.5 px-3 py-2 rounded-lg hover:bg-zinc-50 cursor-pointer transition-all duration-150 ${collapsed ? 'justify-center' : ''}`}>
          <div className="w-7 h-7 rounded-full gradient-instagram flex items-center justify-center shrink-0">
            <span className="text-white text-[10px] font-bold">AC</span>
          </div>
          {!collapsed && (
            <div className="flex-1 min-w-0">
              <p className="text-xs font-semibold text-zinc-800 truncate leading-tight">Alex Chen</p>
              <p className="text-[10px] text-zinc-400 truncate">Pro Plan</p>
            </div>
          )}
        </div>
      </div>

      {/* Collapse toggle */}
      <button
        onClick={() => setCollapsed(!collapsed)}
        className={`
          absolute -right-3 top-20 w-6 h-6 rounded-full bg-white border border-zinc-200
          flex items-center justify-center shadow-sm hover:shadow-card-hover
          text-zinc-400 hover:text-zinc-700 transition-all duration-150 z-10
        `}
        aria-label={collapsed ? 'Expand sidebar' : 'Collapse sidebar'}
      >
        {collapsed ? <ChevronRight size={12} /> : <ChevronLeft size={12} />}
      </button>
    </aside>
  );
}