'use client';

import {
  RadialBarChart, RadialBar, ResponsiveContainer, Tooltip, Legend,
} from 'recharts';
import { PieChart } from 'lucide-react';

// TODO: Backend — GET /api/analytics/sharer-breakdown?accountId=alex.creates
const sharerTypeData = [
  { name: 'Followers', value: 1243, fill: '#7C3AED', pct: 59.1 },
  { name: 'Non-Followers', value: 621, fill: '#EC4899', pct: 29.5 },
  { name: 'Verified / Influencer', value: 240, fill: '#F97316', pct: 11.4 },
];

const shareMethodData = [
  { label: 'DM to friend', count: 1891, pct: 47, color: '#7C3AED' },
  { label: 'Story repost', count: 1104, pct: 28, color: '#EC4899' },
  { label: 'Feed share', count: 594, pct: 15, color: '#F97316' },
  { label: 'External link', count: 258, pct: 10, color: '#06B6D4' },
];

const CustomTooltip = ({ active, payload }: any) => {
  if (!active || !payload?.length) return null;
  const d = payload[0].payload;
  return (
    <div className="bg-white border border-zinc-200 rounded-xl shadow-dropdown p-3 text-sm">
      <p className="font-semibold text-zinc-800 mb-1">{d.name}</p>
      <p className="text-zinc-600 tabular-nums">{d.value.toLocaleString()} sharers</p>
      <p className="text-zinc-400 text-xs">{d.pct}% of total</p>
    </div>
  );
};

export default function SharerTypeChart() {
  const total = sharerTypeData.reduce((s, d) => s + d.value, 0);

  return (
    <div className="bg-white rounded-xl border border-zinc-200 shadow-card p-5 h-full flex flex-col">
      <div className="flex items-center gap-2 mb-1">
        <PieChart size={15} className="text-violet-500" />
        <h3 className="text-[15px] font-semibold text-zinc-900">Sharer Breakdown</h3>
      </div>
      <p className="text-xs text-zinc-400 mb-4">Who is sharing your content today</p>

      {/* Radial chart */}
      <div className="relative flex-1 min-h-[180px]">
        <ResponsiveContainer width="100%" height={180}>
          <RadialBarChart
            cx="50%"
            cy="50%"
            innerRadius="35%"
            outerRadius="85%"
            barSize={14}
            data={sharerTypeData}
            startAngle={90}
            endAngle={-270}
          >
            <RadialBar dataKey="value" cornerRadius={6} background={{ fill: '#f4f4f5' }} />
            <Tooltip content={<CustomTooltip />} />
          </RadialBarChart>
        </ResponsiveContainer>
        {/* Center label */}
        <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
          <span className="text-2xl font-bold text-zinc-900 tabular-nums">{total.toLocaleString()}</span>
          <span className="text-[10px] text-zinc-400 font-medium">total sharers</span>
        </div>
      </div>

      {/* Legend */}
      <div className="mt-3 space-y-2">
        {sharerTypeData.map((d) => (
          <div key={d.name} className="flex items-center justify-between">
            <div className="flex items-center gap-2">
              <span className="w-2.5 h-2.5 rounded-full shrink-0" style={{ backgroundColor: d.fill }} />
              <span className="text-[12px] text-zinc-600">{d.name}</span>
            </div>
            <div className="flex items-center gap-2">
              <span className="text-[12px] font-semibold text-zinc-800 tabular-nums">{d.value.toLocaleString()}</span>
              <span className="text-[10px] text-zinc-400 w-8 text-right">{d.pct}%</span>
            </div>
          </div>
        ))}
      </div>

      {/* Share method mini breakdown */}
      <div className="mt-4 pt-4 border-t border-zinc-100">
        <p className="text-[11px] font-semibold text-zinc-400 uppercase tracking-wider mb-2">Share Method</p>
        {shareMethodData.map((m) => (
          <div key={m.label} className="mb-2">
            <div className="flex justify-between text-[11px] mb-0.5">
              <span className="text-zinc-600">{m.label}</span>
              <span className="font-medium text-zinc-700 tabular-nums">{m.pct}%</span>
            </div>
            <div className="h-1.5 bg-zinc-100 rounded-full overflow-hidden">
              <div
                className="h-full rounded-full transition-all duration-700"
                style={{ width: `${m.pct}%`, backgroundColor: m.color }}
              />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}