'use client';

import { useState } from 'react';
import { X, Instagram, Plus, Trash2, User, AtSign } from 'lucide-react';

export interface InstagramAccount {
  id: string;
  username: string;
  displayName: string;
  addedAt: string;
}

interface ManualAccountModalProps {
  isOpen: boolean;
  onClose: () => void;
  accounts: InstagramAccount[];
  onAddAccount: (account: InstagramAccount) => void;
  onRemoveAccount: (id: string) => void;
}

export default function ManualAccountModal({
  isOpen,
  onClose,
  accounts,
  onAddAccount,
  onRemoveAccount,
}: ManualAccountModalProps) {
  const [username, setUsername] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [error, setError] = useState('');

  if (!isOpen) return null;

  const handleAdd = () => {
    const trimmedUsername = username.trim().replace(/^@/, '');
    const trimmedDisplay = displayName.trim();

    if (!trimmedUsername) {
      setError('Instagram username is required.');
      return;
    }
    if (!/^[a-zA-Z0-9._]{1,30}$/.test(trimmedUsername)) {
      setError('Enter a valid Instagram username (letters, numbers, . and _ only).');
      return;
    }
    if (accounts.some((a) => a.username.toLowerCase() === trimmedUsername.toLowerCase())) {
      setError('This account has already been added.');
      return;
    }

    const newAccount: InstagramAccount = {
      id: `${Date.now()}-${Math.random().toString(36).slice(2)}`,
      username: trimmedUsername,
      displayName: trimmedDisplay || trimmedUsername,
      addedAt: new Date().toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }),
    };

    onAddAccount(newAccount);
    setUsername('');
    setDisplayName('');
    setError('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') handleAdd();
    if (e.key === 'Escape') onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      {/* Backdrop */}
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={onClose}
      />

      {/* Modal */}
      <div className="relative bg-white rounded-2xl shadow-2xl w-full max-w-md border border-zinc-200 overflow-hidden">
        {/* Header */}
        <div className="flex items-center justify-between px-6 py-4 border-b border-zinc-100">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-pink-500 to-violet-600 flex items-center justify-center">
              <Instagram size={15} className="text-white" />
            </div>
            <div>
              <h2 className="text-base font-semibold text-zinc-900">Manage Accounts</h2>
              <p className="text-xs text-zinc-400">Add Instagram accounts to track</p>
            </div>
          </div>
          <button
            onClick={onClose}
            className="w-7 h-7 flex items-center justify-center rounded-lg hover:bg-zinc-100 text-zinc-400 hover:text-zinc-600 transition-colors"
          >
            <X size={15} />
          </button>
        </div>

        {/* Add Account Form */}
        <div className="px-6 py-4 border-b border-zinc-100 bg-zinc-50/50">
          <p className="text-xs font-medium text-zinc-500 uppercase tracking-wide mb-3">Add New Account</p>
          <div className="space-y-2.5">
            <div className="relative">
              <AtSign size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400" />
              <input
                type="text"
                value={username}
                onChange={(e) => { setUsername(e.target.value); setError(''); }}
                onKeyDown={handleKeyDown}
                placeholder="instagram_username"
                className="w-full pl-8 pr-3 py-2.5 text-sm border border-zinc-200 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-violet-500/30 focus:border-violet-400 placeholder:text-zinc-300 text-zinc-800 transition-all"
              />
            </div>
            <div className="relative">
              <User size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-400" />
              <input
                type="text"
                value={displayName}
                onChange={(e) => setDisplayName(e.target.value)}
                onKeyDown={handleKeyDown}
                placeholder="Display name (optional)"
                className="w-full pl-8 pr-3 py-2.5 text-sm border border-zinc-200 rounded-lg bg-white focus:outline-none focus:ring-2 focus:ring-violet-500/30 focus:border-violet-400 placeholder:text-zinc-300 text-zinc-800 transition-all"
              />
            </div>
            {error && (
              <p className="text-xs text-red-500 flex items-center gap-1">
                <span className="inline-block w-1 h-1 rounded-full bg-red-500" />
                {error}
              </p>
            )}
            <button
              onClick={handleAdd}
              className="w-full flex items-center justify-center gap-1.5 py-2.5 rounded-lg bg-violet-600 hover:bg-violet-700 text-white text-sm font-medium transition-all active:scale-[0.98]"
            >
              <Plus size={14} />
              Add Account
            </button>
          </div>
        </div>

        {/* Account List */}
        <div className="px-6 py-4 max-h-64 overflow-y-auto">
          {accounts.length === 0 ? (
            <div className="flex flex-col items-center justify-center py-8 text-center">
              <div className="w-10 h-10 rounded-full bg-zinc-100 flex items-center justify-center mb-2.5">
                <Instagram size={18} className="text-zinc-300" />
              </div>
              <p className="text-sm text-zinc-400">No accounts added yet</p>
              <p className="text-xs text-zinc-300 mt-0.5">Add an Instagram username above to get started</p>
            </div>
          ) : (
            <div className="space-y-2">
              <p className="text-xs font-medium text-zinc-500 uppercase tracking-wide mb-2">
                Tracked Accounts ({accounts.length})
              </p>
              {accounts.map((account) => (
                <div
                  key={account.id}
                  className="flex items-center justify-between p-3 rounded-xl border border-zinc-100 bg-white hover:border-zinc-200 transition-colors group"
                >
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-gradient-to-br from-pink-400 to-violet-500 flex items-center justify-center text-white text-xs font-semibold">
                      {account.displayName.charAt(0).toUpperCase()}
                    </div>
                    <div>
                      <p className="text-sm font-medium text-zinc-800">{account.displayName}</p>
                      <p className="text-xs text-zinc-400">@{account.username} · Added {account.addedAt}</p>
                    </div>
                  </div>
                  <button
                    onClick={() => onRemoveAccount(account.id)}
                    className="w-7 h-7 flex items-center justify-center rounded-lg text-zinc-300 hover:text-red-500 hover:bg-red-50 transition-colors opacity-0 group-hover:opacity-100"
                    title="Remove account"
                  >
                    <Trash2 size={13} />
                  </button>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Footer */}
        <div className="px-6 py-3 border-t border-zinc-100 bg-zinc-50/50 flex justify-end">
          <button
            onClick={onClose}
            className="px-4 py-2 text-sm font-medium text-zinc-600 hover:text-zinc-800 hover:bg-zinc-100 rounded-lg transition-colors"
          >
            Done
          </button>
        </div>
      </div>
    </div>
  );
}
