'use client';

import { useState } from 'react';
import { RefreshCw, Download, Calendar, ChevronDown, Instagram, Wifi, UserPlus, ChevronRight } from 'lucide-react';
import { toast } from 'sonner';
import { InstagramAccount } from './ManualAccountModal';

const dateRanges = ['Last 24 hours', 'Last 7 days', 'Last 30 days', 'Last 90 days', 'Custom range'];
const contentFilters = ['All Content', 'Reels', 'Feed Posts', 'Stories', 'Carousels'];

interface DashboardHeaderProps {
  accounts: InstagramAccount[];
  onManageAccounts: () => void;
}

export default function DashboardHeader({ accounts, onManageAccounts }: DashboardHeaderProps) {
  const [selectedRange, setSelectedRange] = useState('Last 7 days');
  const [selectedContent, setSelectedContent] = useState('All Content');
  const [selectedAccount, setSelectedAccount] = useState<InstagramAccount | null>(accounts[0] ?? null);
  const [rangeOpen, setRangeOpen] = useState(false);
  const [contentOpen, setContentOpen] = useState(false);
  const [accountOpen, setAccountOpen] = useState(false);
  const [refreshing, setRefreshing] = useState(false);

  // Keep selectedAccount in sync when accounts list changes
  const activeAccount = accounts.find((a) => a.id === selectedAccount?.id) ?? accounts[0] ?? null;

  const handleRefresh = async () => {
    setRefreshing(true);
    // TODO: Backend — POST /api/analytics/refresh to trigger fresh share data pull from Instagram Graph API
    await new Promise((r) => setTimeout(r, 1400));
    setRefreshing(false);
    toast?.success('Share data refreshed', {
      description: 'All metrics updated as of right now.',
    });
  };

  const handleExport = () => {
    // TODO: Backend — GET /api/analytics/export?range=7d&format=csv to download share report
    toast?.success('Exporting report…', {
      description: 'Your CSV will be ready in a moment.',
    });
  };

  return (
    <div className="flex flex-col sm:flex-row sm:items-start sm:justify-between gap-4 mb-6">
      {/* Left: Title + live indicator */}
      <div>
        <div className="flex items-center gap-2.5 mb-1">
          <h1 className="text-2xl font-semibold text-zinc-900 tracking-tight">Share Tracking</h1>
          <span className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-green-50 border border-green-200 text-green-700 text-[11px] font-medium">
            <Wifi size={10} className="animate-pulse" />
            Live
          </span>
        </div>
        {/* Account selector */}
        <div className="relative flex items-center gap-2">
          <Instagram size={13} className="text-pink-400 shrink-0" />
          {accounts.length <= 1 ? (
            <span className="text-sm text-zinc-400">
              @{activeAccount?.username ?? 'no account'}
              <span className="text-zinc-200 mx-1.5">·</span>
              <span className="text-zinc-500 font-medium">Last updated 2 min ago</span>
            </span>
          ) : (
            <button
              onClick={() => { setAccountOpen(!accountOpen); setRangeOpen(false); setContentOpen(false); }}
              className="flex items-center gap-1 text-sm text-zinc-500 hover:text-zinc-700 transition-colors"
            >
              <span className="font-medium text-zinc-700">@{activeAccount?.username ?? '—'}</span>
              <ChevronDown size={12} className={`text-zinc-400 transition-transform ${accountOpen ? 'rotate-180' : ''}`} />
            </button>
          )}
          {accountOpen && accounts.length > 1 && (
            <div className="absolute left-0 top-full mt-1.5 w-52 bg-white border border-zinc-200 rounded-lg shadow-dropdown z-20 py-1 fade-in">
              {accounts.map((acc) => (
                <button
                  key={acc.id}
                  onClick={() => { setSelectedAccount(acc); setAccountOpen(false); }}
                  className={`w-full text-left px-3 py-2 text-sm flex items-center gap-2 transition-colors ${activeAccount?.id === acc.id ? 'text-violet-700 bg-violet-50 font-medium' : 'text-zinc-700 hover:bg-zinc-50'}`}
                >
                  <div className="w-5 h-5 rounded-full bg-gradient-to-br from-pink-400 to-violet-500 flex items-center justify-center text-white text-[9px] font-bold shrink-0">
                    {acc.displayName.charAt(0).toUpperCase()}
                  </div>
                  <span>@{acc.username}</span>
                </button>
              ))}
              <div className="border-t border-zinc-100 mt-1 pt-1">
                <button
                  onClick={() => { setAccountOpen(false); onManageAccounts(); }}
                  className="w-full text-left px-3 py-2 text-sm text-violet-600 hover:bg-violet-50 flex items-center gap-1.5 font-medium transition-colors"
                >
                  <UserPlus size={12} />
                  Manage accounts
                  <ChevronRight size={11} className="ml-auto text-violet-400" />
                </button>
              </div>
            </div>
          )}
          <span className="text-zinc-200">·</span>
          <span className="text-sm text-zinc-400">Last updated <span className="text-zinc-500 font-medium">2 min ago</span></span>
        </div>
      </div>

      {/* Right: Controls */}
      <div className="flex flex-wrap items-center gap-2">
        {/* Add / Manage Accounts */}
        <button
          onClick={onManageAccounts}
          className="flex items-center gap-1.5 px-3 py-2 rounded-lg border border-violet-200 bg-violet-50 text-sm font-medium text-violet-700 hover:bg-violet-100 hover:border-violet-300 transition-all duration-150 shadow-card"
        >
          <UserPlus size={13} />
          {accounts.length === 0 ? 'Add Account' : `Accounts (${accounts.length})`}
        </button>

        {/* Content type filter */}
        <div className="relative">
          <button
            onClick={() => { setContentOpen(!contentOpen); setRangeOpen(false); setAccountOpen(false); }}
            className="flex items-center gap-1.5 px-3 py-2 rounded-lg border border-zinc-200 bg-white text-sm font-medium text-zinc-700 hover:border-zinc-300 hover:bg-zinc-50 transition-all duration-150 shadow-card"
          >
            <span>{selectedContent}</span>
            <ChevronDown size={13} className={`text-zinc-400 transition-transform duration-150 ${contentOpen ? 'rotate-180' : ''}`} />
          </button>
          {contentOpen && (
            <div className="absolute right-0 top-full mt-1.5 w-44 bg-white border border-zinc-200 rounded-lg shadow-dropdown z-20 py-1 fade-in">
              {contentFilters?.map((f) => (
                <button
                  key={f}
                  onClick={() => { setSelectedContent(f); setContentOpen(false); }}
                  className={`w-full text-left px-3 py-2 text-sm transition-colors ${selectedContent === f ? 'text-violet-700 bg-violet-50 font-medium' : 'text-zinc-700 hover:bg-zinc-50'}`}
                >
                  {f}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Date range */}
        <div className="relative">
          <button
            onClick={() => { setRangeOpen(!rangeOpen); setContentOpen(false); setAccountOpen(false); }}
            className="flex items-center gap-1.5 px-3 py-2 rounded-lg border border-zinc-200 bg-white text-sm font-medium text-zinc-700 hover:border-zinc-300 hover:bg-zinc-50 transition-all duration-150 shadow-card"
          >
            <Calendar size={13} className="text-zinc-400" />
            <span>{selectedRange}</span>
            <ChevronDown size={13} className={`text-zinc-400 transition-transform duration-150 ${rangeOpen ? 'rotate-180' : ''}`} />
          </button>
          {rangeOpen && (
            <div className="absolute right-0 top-full mt-1.5 w-48 bg-white border border-zinc-200 rounded-lg shadow-dropdown z-20 py-1 fade-in">
              {dateRanges?.map((r) => (
                <button
                  key={r}
                  onClick={() => { setSelectedRange(r); setRangeOpen(false); }}
                  className={`w-full text-left px-3 py-2 text-sm transition-colors ${selectedRange === r ? 'text-violet-700 bg-violet-50 font-medium' : 'text-zinc-700 hover:bg-zinc-50'}`}
                >
                  {r}
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Refresh */}
        <button
          onClick={handleRefresh}
          disabled={refreshing}
          className="flex items-center gap-1.5 px-3 py-2 rounded-lg border border-zinc-200 bg-white text-sm font-medium text-zinc-700 hover:border-zinc-300 hover:bg-zinc-50 transition-all duration-150 shadow-card disabled:opacity-60 active:scale-95"
        >
          <RefreshCw size={13} className={`text-zinc-400 ${refreshing ? 'animate-spin' : ''}`} />
          {refreshing ? 'Refreshing…' : 'Refresh'}
        </button>

        {/* Export */}
        <button
          onClick={handleExport}
          className="flex items-center gap-1.5 px-3 py-2 rounded-lg bg-violet-600 text-white text-sm font-medium hover:bg-violet-700 transition-all duration-150 shadow-sm active:scale-95"
        >
          <Download size={13} />
          Export Report
        </button>
      </div>
    </div>
  );
}