'use client';

import { useState } from 'react';
import AppLayout from '@/components/AppLayout';
import DashboardHeader from './components/DashboardHeader';
import KPIBentoGrid from './components/KPIBentoGrid';
import ShareTimelineChart from './components/ShareTimelineChart';
import SharerTypeChart from './components/SharerTypeChart';
import RecentSharersFeed from './components/RecentSharersFeed';
import TopSharedPostsTable from './components/TopSharedPostsTable';
import ManualAccountModal, { InstagramAccount } from './components/ManualAccountModal';

export default function ShareTrackingDashboard() {
  const [accountModalOpen, setAccountModalOpen] = useState(false);
  const [accounts, setAccounts] = useState<InstagramAccount[]>([
    {
      id: 'default-1',
      username: 'alex.creates',
      displayName: 'Alex Creates',
      addedAt: 'Mar 1, 2026',
    },
  ]);

  const handleAddAccount = (account: InstagramAccount) => {
    setAccounts((prev) => [...prev, account]);
  };

  const handleRemoveAccount = (id: string) => {
    setAccounts((prev) => prev.filter((a) => a.id !== id));
  };

  return (
    <AppLayout>
      <div className="px-6 lg:px-8 xl:px-10 2xl:px-12 py-6 max-w-screen-2xl mx-auto w-full">
        <DashboardHeader
          accounts={accounts}
          onManageAccounts={() => setAccountModalOpen(true)}
        />
        <KPIBentoGrid />
        {/* Charts row */}
        <div className="mt-6 grid grid-cols-1 xl:grid-cols-3 gap-5">
          <div className="xl:col-span-2">
            <ShareTimelineChart />
          </div>
          <div className="xl:col-span-1">
            <SharerTypeChart />
          </div>
        </div>
        {/* Bottom row */}
        <div className="mt-5 grid grid-cols-1 xl:grid-cols-5 gap-5">
          <div className="xl:col-span-3">
            <TopSharedPostsTable />
          </div>
          <div className="xl:col-span-2">
            <RecentSharersFeed />
          </div>
        </div>
      </div>

      <ManualAccountModal
        isOpen={accountModalOpen}
        onClose={() => setAccountModalOpen(false)}
        accounts={accounts}
        onAddAccount={handleAddAccount}
        onRemoveAccount={handleRemoveAccount}
      />
    </AppLayout>
  );
}