'use client';

import { useState } from 'react';
import { ArrowUpDown, ArrowUp, ArrowDown, Zap, TrendingDown, Eye, ExternalLink, Share2, Film, Image as ImageIcon, BookOpen } from 'lucide-react';
import { toast } from 'sonner';
import AppImage from '@/components/ui/AppImage';

type SortKey = 'totalShares' | 'uniqueSharers' | 'velocity' | 'reach';
type SortDir = 'asc' | 'desc';
type PostStatus = 'Viral' | 'Trending' | 'Active' | 'Declining' | 'Archived';
type PostType = 'Reel' | 'Post' | 'Carousel' | 'Story';

interface Post {
  id: string;
  thumbnail: string;
  thumbnailAlt: string;
  caption: string;
  type: PostType;
  publishedAt: string;
  totalShares: number;
  uniqueSharers: number;
  velocity: number;
  reach: number;
  shareToReach: number;
  status: PostStatus;
}

// TODO: Backend — GET /api/posts/top-shared?accountId=alex.creates&sortBy=totalShares&limit=10
const posts: Post[] = [
  { id: 'p1', thumbnail: 'https://picsum.photos/seed/reel1/60/60', thumbnailAlt: 'Person doing morning yoga in sunlit room', caption: 'Morning routine vlog ✨ 5am wake up → workout → journaling', type: 'Reel', publishedAt: 'Mar 15', totalShares: 1547, uniqueSharers: 1102, velocity: 47, reach: 84200, shareToReach: 1.84, status: 'Viral' },
  { id: 'p2', thumbnail: 'https://picsum.photos/seed/post2/60/60', thumbnailAlt: 'Stylish outfit on city street', caption: 'NYC street style lookbook — spring edition 🗽', type: 'Post', publishedAt: 'Mar 14', totalShares: 988, uniqueSharers: 741, velocity: 28, reach: 62100, shareToReach: 1.59, status: 'Trending' },
  { id: 'p3', thumbnail: 'https://picsum.photos/seed/reel3/60/60', thumbnailAlt: 'Camera lens close-up with editing software on screen', caption: 'Behind the lens: my full editing workflow 🎬', type: 'Reel', publishedAt: 'Mar 13', totalShares: 724, uniqueSharers: 588, velocity: 19, reach: 51400, shareToReach: 1.41, status: 'Active' },
  { id: 'p4', thumbnail: 'https://picsum.photos/seed/home4/60/60', thumbnailAlt: 'Minimalist living room with white walls and plants', caption: 'Minimalist home tour 🏠 — how I redesigned my studio', type: 'Reel', publishedAt: 'Mar 12', totalShares: 612, uniqueSharers: 480, velocity: 14, reach: 44800, shareToReach: 1.37, status: 'Active' },
  { id: 'p5', thumbnail: 'https://picsum.photos/seed/carousel5/60/60', thumbnailAlt: 'Flat lay of productivity tools and notebook', caption: '10 apps that changed how I work — swipe for full list →', type: 'Carousel', publishedAt: 'Mar 11', totalShares: 445, uniqueSharers: 361, velocity: 8, reach: 38900, shareToReach: 1.14, status: 'Declining' },
  { id: 'p6', thumbnail: 'https://picsum.photos/seed/reel6/60/60', thumbnailAlt: 'Sunset timelapse over city skyline', caption: 'Golden hour in Manhattan — no filter needed 🌅', type: 'Reel', publishedAt: 'Mar 10', totalShares: 388, uniqueSharers: 301, velocity: 5, reach: 29300, shareToReach: 1.32, status: 'Declining' },
  { id: 'p7', thumbnail: 'https://picsum.photos/seed/post7/60/60', thumbnailAlt: 'Healthy meal prep containers on kitchen counter', caption: 'Sunday meal prep for the whole week 🥗', type: 'Post', publishedAt: 'Mar 9', totalShares: 201, uniqueSharers: 178, velocity: 2, reach: 18700, shareToReach: 1.07, status: 'Archived' },
  { id: 'p8', thumbnail: 'https://picsum.photos/seed/carousel8/60/60', thumbnailAlt: 'Travel photos collage from Japan trip', caption: 'Japan trip recap — 14 days, 8 cities, 2000+ photos 🇯🇵', type: 'Carousel', publishedAt: 'Mar 8', totalShares: 155, uniqueSharers: 134, velocity: 1, reach: 14200, shareToReach: 1.09, status: 'Archived' },
];

const statusConfig: Record<PostStatus, { label: string; color: string; bg: string; border: string }> = {
  Viral: { label: 'Viral 🔥', color: 'text-violet-700', bg: 'bg-violet-50', border: 'border-violet-200' },
  Trending: { label: 'Trending', color: 'text-pink-700', bg: 'bg-pink-50', border: 'border-pink-200' },
  Active: { label: 'Active', color: 'text-green-700', bg: 'bg-green-50', border: 'border-green-200' },
  Declining: { label: 'Declining', color: 'text-amber-700', bg: 'bg-amber-50', border: 'border-amber-200' },
  Archived: { label: 'Archived', color: 'text-zinc-500', bg: 'bg-zinc-50', border: 'border-zinc-200' },
};

const typeConfig: Record<PostType, { icon: React.ElementType; color: string }> = {
  Reel: { icon: Film, color: 'text-violet-500' },
  Post: { icon: ImageIcon, color: 'text-pink-500' },
  Carousel: { icon: BookOpen, color: 'text-orange-500' },
  Story: { icon: Zap, color: 'text-cyan-500' },
};

export default function TopSharedPostsTable() {
  const [sortKey, setSortKey] = useState<SortKey>('totalShares');
  const [sortDir, setSortDir] = useState<SortDir>('desc');
  const [hoveredRow, setHoveredRow] = useState<string | null>(null);

  const handleSort = (key: SortKey) => {
    if (sortKey === key) setSortDir(sortDir === 'desc' ? 'asc' : 'desc');
    else { setSortKey(key); setSortDir('desc'); }
  };

  const sorted = [...posts].sort((a, b) => {
    const mult = sortDir === 'desc' ? -1 : 1;
    return mult * (a[sortKey] - b[sortKey]);
  });

  const SortIcon = ({ col }: { col: SortKey }) => {
    if (sortKey !== col) return <ArrowUpDown size={12} className="text-zinc-300 ml-1 inline" />;
    return sortDir === 'desc'
      ? <ArrowDown size={12} className="text-violet-500 ml-1 inline" />
      : <ArrowUp size={12} className="text-violet-500 ml-1 inline" />;
  };

  return (
    <div className="bg-white rounded-xl border border-zinc-200 shadow-card flex flex-col" style={{ maxHeight: 620 }}>
      {/* Header */}
      <div className="px-5 pt-5 pb-3 border-b border-zinc-100 flex items-center justify-between">
        <div>
          <h3 className="text-[15px] font-semibold text-zinc-900">Top Shared Posts</h3>
          <p className="text-xs text-zinc-400 mt-0.5">Ranked by total shares · all content types</p>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-xs text-zinc-400">{posts.length} posts</span>
          <button
            onClick={() => toast.success('Opening post analytics…')}
            className="text-xs font-medium text-violet-600 hover:text-violet-800 px-2.5 py-1.5 rounded-lg hover:bg-violet-50 transition-colors"
          >
            View all
          </button>
        </div>
      </div>

      {/* Table */}
      <div className="overflow-auto scrollbar-thin flex-1">
        <table className="w-full min-w-[600px] text-sm">
          <thead>
            <tr className="border-b border-zinc-100 bg-zinc-50/60">
              <th className="text-left px-5 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider w-[280px]">Post</th>
              <th className="text-right px-4 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider cursor-pointer hover:text-zinc-600 select-none whitespace-nowrap" onClick={() => handleSort('totalShares')}>
                Shares <SortIcon col="totalShares" />
              </th>
              <th className="text-right px-4 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider cursor-pointer hover:text-zinc-600 select-none whitespace-nowrap" onClick={() => handleSort('uniqueSharers')}>
                Unique <SortIcon col="uniqueSharers" />
              </th>
              <th className="text-right px-4 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider cursor-pointer hover:text-zinc-600 select-none whitespace-nowrap" onClick={() => handleSort('velocity')}>
                /hr <SortIcon col="velocity" />
              </th>
              <th className="text-right px-4 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider cursor-pointer hover:text-zinc-600 select-none whitespace-nowrap" onClick={() => handleSort('reach')}>
                Reach <SortIcon col="reach" />
              </th>
              <th className="px-4 py-3 text-[11px] font-semibold text-zinc-400 uppercase tracking-wider text-center">Status</th>
              <th className="px-4 py-3 w-10" />
            </tr>
          </thead>
          <tbody>
            {sorted.map((post, idx) => {
              const statusConf = statusConfig[post.status];
              const typeConf = typeConfig[post.type];
              const TypeIcon = typeConf.icon;
              const isHovered = hoveredRow === post.id;

              return (
                <tr
                  key={post.id}
                  onMouseEnter={() => setHoveredRow(post.id)}
                  onMouseLeave={() => setHoveredRow(null)}
                  className={`border-b border-zinc-50 transition-colors duration-100 ${isHovered ? 'bg-zinc-50/80' : idx % 2 === 0 ? 'bg-white' : 'bg-zinc-50/30'}`}
                >
                  {/* Post cell */}
                  <td className="px-5 py-3">
                    <div className="flex items-center gap-3">
                      <div className="relative shrink-0">
                        <div className="w-10 h-10 rounded-lg overflow-hidden border border-zinc-200">
                          <AppImage
                            src={post.thumbnail}
                            alt={post.thumbnailAlt}
                            width={40}
                            height={40}
                            className="w-full h-full object-cover"
                            unoptimized
                          />
                        </div>
                        <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full bg-white border border-zinc-200 flex items-center justify-center`}>
                          <TypeIcon size={9} className={typeConf.color} />
                        </div>
                      </div>
                      <div className="min-w-0">
                        <p className="text-[13px] font-medium text-zinc-800 truncate max-w-[180px] leading-tight">{post.caption}</p>
                        <p className="text-[11px] text-zinc-400 mt-0.5">{post.publishedAt} · S/R: <span className="font-medium text-zinc-600">{post.shareToReach}%</span></p>
                      </div>
                    </div>
                  </td>
                  {/* Shares */}
                  <td className="px-4 py-3 text-right">
                    <span className="text-[13px] font-semibold text-zinc-800 tabular-nums">{post.totalShares.toLocaleString()}</span>
                  </td>
                  {/* Unique */}
                  <td className="px-4 py-3 text-right">
                    <span className="text-[13px] text-zinc-600 tabular-nums">{post.uniqueSharers.toLocaleString()}</span>
                  </td>
                  {/* Velocity */}
                  <td className="px-4 py-3 text-right">
                    <span className={`text-[13px] font-medium tabular-nums flex items-center justify-end gap-1 ${post.velocity >= 20 ? 'text-violet-600' : post.velocity >= 5 ? 'text-zinc-600' : 'text-zinc-400'}`}>
                      {post.velocity >= 5 ? <Zap size={10} className="text-amber-400" /> : <TrendingDown size={10} className="text-zinc-300" />}
                      {post.velocity}
                    </span>
                  </td>
                  {/* Reach */}
                  <td className="px-4 py-3 text-right">
                    <span className="text-[13px] text-zinc-600 tabular-nums">{post.reach >= 1000 ? `${(post.reach / 1000).toFixed(1)}K` : post.reach}</span>
                  </td>
                  {/* Status */}
                  <td className="px-4 py-3 text-center">
                    <span className={`inline-flex items-center text-[10px] font-semibold px-2 py-0.5 rounded-full border ${statusConf.color} ${statusConf.bg} ${statusConf.border} whitespace-nowrap`}>
                      {statusConf.label}
                    </span>
                  </td>
                  {/* Actions */}
                  <td className="px-4 py-3">
                    <div className={`flex items-center gap-1 transition-opacity duration-100 ${isHovered ? 'opacity-100' : 'opacity-0'}`}>
                      <button
                        onClick={() => toast.success(`Opening analytics for "${post.caption.slice(0, 30)}…"`)}
                        className="p-1.5 rounded-lg hover:bg-zinc-100 text-zinc-400 hover:text-zinc-700 transition-colors"
                        title="View share analytics"
                      >
                        <Eye size={13} />
                      </button>
                      <button
                        onClick={() => toast.success('Opening in Instagram…')}
                        className="p-1.5 rounded-lg hover:bg-zinc-100 text-zinc-400 hover:text-zinc-700 transition-colors"
                        title="Open in Instagram"
                      >
                        <ExternalLink size={13} />
                      </button>
                    </div>
                  </td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>

      {/* Footer summary */}
      <div className="px-5 py-3 border-t border-zinc-100 flex items-center justify-between">
        <div className="flex items-center gap-4 text-xs text-zinc-400">
          <span className="flex items-center gap-1"><Share2 size={11} className="text-violet-400" /> <span className="tabular-nums font-medium text-zinc-600">{posts.reduce((s, p) => s + p.totalShares, 0).toLocaleString()}</span> total</span>
          <span className="flex items-center gap-1"><Eye size={11} className="text-pink-400" /> <span className="tabular-nums font-medium text-zinc-600">{(posts.reduce((s, p) => s + p.reach, 0) / 1000).toFixed(0)}K</span> reach</span>
        </div>
        <span className="text-xs text-zinc-400">Showing {posts.length} posts</span>
      </div>
    </div>
  );
}