'use client';

import { useState } from 'react';
import Sidebar from './Sidebar';
import { Menu, X } from 'lucide-react';

interface AppLayoutProps {
  children: React.ReactNode;
}

export default function AppLayout({ children }: AppLayoutProps) {
  const [mobileSidebarOpen, setMobileSidebarOpen] = useState(false);

  return (
    <div className="min-h-screen bg-[hsl(var(--background))] flex">
      {/* Desktop Sidebar */}
      <div className="hidden lg:block">
        <Sidebar />
      </div>

      {/* Mobile Sidebar Overlay */}
      {mobileSidebarOpen && (
        <div
          className="fixed inset-0 z-40 lg:hidden"
          onClick={() => setMobileSidebarOpen(false)}
        >
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" />
        </div>
      )}

      {/* Mobile Sidebar */}
      <div
        className={`
          fixed left-0 top-0 h-full z-50 lg:hidden
          transition-transform duration-300 ease-in-out
          ${mobileSidebarOpen ? 'translate-x-0' : '-translate-x-full'}
        `}
      >
        <Sidebar />
        <button
          onClick={() => setMobileSidebarOpen(false)}
          className="absolute top-4 right-[-40px] w-8 h-8 rounded-full bg-white shadow flex items-center justify-center"
        >
          <X size={16} className="text-zinc-600" />
        </button>
      </div>

      {/* Main content */}
      <div className="flex-1 lg:ml-60 min-w-0 flex flex-col transition-all duration-300">
        {/* Mobile topbar */}
        <div className="lg:hidden flex items-center h-14 px-4 bg-white border-b border-zinc-200 sticky top-0 z-20">
          <button
            onClick={() => setMobileSidebarOpen(true)}
            className="p-2 rounded-lg hover:bg-zinc-100 text-zinc-600 transition-colors"
          >
            <Menu size={20} />
          </button>
          <span className="ml-3 font-semibold text-zinc-900 text-sm">
            InstaShare<span className="text-violet-600">Tracker</span>
          </span>
        </div>

        {/* Page content */}
        <main className="flex-1 overflow-auto">
          {children}
        </main>
      </div>
    </div>
  );
}