'use client';

import { useState, useEffect } from 'react';
import { Share2, Zap, Users, Repeat2, UserPlus, ArrowUpRight, ArrowDownRight, Minus, AlertTriangle } from 'lucide-react';
import Icon from '@/components/ui/AppIcon';


interface KPICard {
  id: string;
  label: string;
  value: string;
  subValue?: string;
  change: number;
  changeLabel: string;
  icon: React.ElementType;
  trend: 'up' | 'down' | 'neutral';
  sentiment: 'positive' | 'negative' | 'warning' | 'neutral';
  hero?: boolean;
  alert?: boolean;
  alertMessage?: string;
  colSpan?: string;
}

const kpiData: KPICard[] = [
  {
    id: 'total-shares',
    label: 'Total Shares Today',
    value: '3,847',
    subValue: 'across 12 posts',
    change: 23.4,
    changeLabel: 'vs yesterday',
    icon: Share2,
    trend: 'up',
    sentiment: 'positive',
    hero: true,
    colSpan: 'col-span-1 md:col-span-2',
  },
  {
    id: 'share-velocity',
    label: 'Share Velocity',
    value: '47/hr',
    subValue: 'peak: 112/hr at 2pm',
    change: 8.1,
    changeLabel: 'vs last 7d avg',
    icon: Zap,
    trend: 'up',
    sentiment: 'positive',
  },
  {
    id: 'unique-sharers',
    label: 'Unique Sharers',
    value: '2,104',
    subValue: '68% first-time sharers',
    change: 15.7,
    changeLabel: 'vs yesterday',
    icon: Users,
    trend: 'up',
    sentiment: 'positive',
  },
  {
    id: 'repeat-sharers',
    label: 'Repeat Sharers',
    value: '318',
    subValue: '15.1% of total sharers',
    change: -4.2,
    changeLabel: 'vs last week',
    icon: Repeat2,
    trend: 'down',
    sentiment: 'warning',
    alert: true,
    alertMessage: 'Advocate engagement dipping',
  },
  {
    id: 'non-follower-rate',
    label: 'Non-Follower Share Rate',
    value: '41.3%',
    subValue: '868 non-followers shared',
    change: 6.8,
    changeLabel: 'organic discovery up',
    icon: UserPlus,
    trend: 'up',
    sentiment: 'positive',
  },
];

export default function KPIBentoGrid() {
  const [loaded, setLoaded] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setLoaded(true), 300);
    return () => clearTimeout(t);
  }, []);

  if (!loaded) {
    return (
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 xl:grid-cols-4 2xl:grid-cols-4 gap-4">
        <div className="col-span-1 md:col-span-2 h-36 animate-pulse bg-zinc-100 rounded-xl" />
        <div className="h-36 animate-pulse bg-zinc-100 rounded-xl" />
        <div className="h-36 animate-pulse bg-zinc-100 rounded-xl" />
        <div className="h-36 animate-pulse bg-zinc-100 rounded-xl" />
        <div className="h-36 animate-pulse bg-zinc-100 rounded-xl" />
      </div>
    );
  }

  const sentimentStyles = {
    positive: {
      card: 'bg-white border-zinc-200',
      badge: 'bg-green-50 text-green-700',
      icon: 'bg-green-50 text-green-600',
      arrow: 'text-green-600',
    },
    negative: {
      card: 'bg-white border-zinc-200',
      badge: 'bg-red-50 text-red-600',
      icon: 'bg-red-50 text-red-500',
      arrow: 'text-red-500',
    },
    warning: {
      card: 'bg-amber-50/60 border-amber-200',
      badge: 'bg-amber-100 text-amber-700',
      icon: 'bg-amber-100 text-amber-600',
      arrow: 'text-amber-600',
    },
    neutral: {
      card: 'bg-white border-zinc-200',
      badge: 'bg-zinc-100 text-zinc-500',
      icon: 'bg-zinc-100 text-zinc-500',
      arrow: 'text-zinc-500',
    },
  };

  return (
    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 xl:grid-cols-4 2xl:grid-cols-4 gap-4 fade-in">
      {kpiData.map((card) => {
        const Icon = card.icon;
        const styles = sentimentStyles[card.sentiment];
        const TrendIcon = card.trend === 'up' ? ArrowUpRight : card.trend === 'down' ? ArrowDownRight : Minus;

        return (
          <div
            key={card.id}
            className={`
              ${card.colSpan || 'col-span-1'}
              relative rounded-xl border p-5 shadow-card hover:shadow-card-hover
              transition-all duration-200 group cursor-default
              ${styles.card}
              ${card.hero ? 'overflow-hidden' : ''}
            `}
          >
            {/* Hero gradient accent */}
            {card.hero && (
              <div className="absolute inset-0 opacity-[0.04] gradient-instagram pointer-events-none" />
            )}

            {/* Alert indicator */}
            {card.alert && (
              <div className="absolute top-3 right-3 flex items-center gap-1 px-2 py-0.5 rounded-full bg-amber-100 border border-amber-200">
                <AlertTriangle size={10} className="text-amber-600" />
                <span className="text-[10px] font-medium text-amber-700">{card.alertMessage}</span>
              </div>
            )}

            <div className="flex items-start justify-between mb-3">
              <div className={`w-9 h-9 rounded-lg flex items-center justify-center ${styles.icon}`}>
                <Icon size={18} />
              </div>
              {!card.alert && (
                <span className={`flex items-center gap-0.5 text-xs font-semibold px-2 py-0.5 rounded-full ${styles.badge}`}>
                  <TrendIcon size={11} />
                  {Math.abs(card.change)}%
                </span>
              )}
            </div>

            <div className={`mb-0.5 ${card.hero ? 'flex items-end gap-3' : ''}`}>
              <span className={`font-bold tabular-nums text-zinc-900 leading-none ${card.hero ? 'text-4xl' : 'text-2xl'}`}>
                {card.value}
              </span>
              {card.hero && card.subValue && (
                <span className="text-sm text-zinc-400 mb-1">{card.subValue}</span>
              )}
            </div>

            <p className="text-[13px] font-medium text-zinc-500 tracking-wide mb-1">{card.label}</p>

            {!card.hero && card.subValue && (
              <p className="text-[11px] text-zinc-400 leading-tight">{card.subValue}</p>
            )}

            <p className={`text-[11px] mt-1 ${styles.arrow}`}>
              <TrendIcon size={10} className="inline mr-0.5" />
              {card.changeLabel}
            </p>
          </div>
        );
      })}
    </div>
  );
}